// shadcn
import { Button } from "@/components/ui/button";

// assets
import { ArrowRightIcon } from "lucide-react";

// constants
const items = [
  {
    id: 1,
    image: "https://cdn.uiable.com/block/portfolio4-1.png",
    title: "Breathe In",
    description:
      "Life isn't about finding yourself, it's about creating yourself.",
  },
  {
    id: 2,
    image: "https://cdn.uiable.com/block/portfolio4-2.png",
    title: "Breathe In",
    description:
      "Life isn't about finding yourself, it's about creating yourself.",
  },
];

//  ------------------------------ | PORTFOLIO 4 | ------------------------------  //

export default function Portfolio4() {
  return (
    <section className="py-20 bg-primary overflow-hidden">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Centered header */}
        <div className="text-center mb-12 flex flex-col gap-6 max-w-md mx-auto">
          <h2 className="text-primary-foreground">
            Great Ideas Start With A Scribble
          </h2>
          <p className="text-primary-foreground/70 max-w-md mx-auto">
            This is a big one and I consider one of the most important, and
            difficult, things for designer to get right.
          </p>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          {items.map((item) => (
            <div
              key={item.id}
              className="relative rounded-4xl overflow-hidden h-80"
            >
              {/* Full-bleed image */}
              <img
                src={item.image}
                alt={item.title}
                className="absolute inset-0 w-full h-full object-cover opacity-95"
              />
              {/* White content box floating over bottom of image */}
              <div className="absolute bottom-4 left-4 right-4 bg-white rounded-2xl p-6 flex items-center justify-between gap-4">
                <div className="flex flex-col gap-4 min-w-0">
                  <h5 className="text-foreground font-bold truncate">
                    {item.title}
                  </h5>
                  <p className="text-muted-foreground text-sm truncate">
                    {item.description}
                  </p>
                </div>
                <Button
                  variant="outline"
                  size="icon"
                  className="shrink-0 rounded-lg hover:bg-primary border border-primary text-primary hover:text-white"
                >
                  <ArrowRightIcon className="size-4" />
                </Button>
              </div>
            </div>
          ))}
        </div>

        {/* Bottom CTA */}
        <div className="flex justify-center mt-10">
          <Button className="bg-yellow-500 text-white hover:bg-yellow-500/90 px-8">
            View Portfolio
          </Button>
        </div>
      </div>
    </section>
  );
}
